// ÉTAPE 1: Construire un index des dossiers (id -> nom)
const items = $input.all();

// Créer un map des dossiers: id -> {nom, id}
const dossiersMap = {};
for (const item of items) {
  const data = item.json;
  if (data && data.id && data.mimeType === 'application/vnd.google-apps.folder') {
    dossiersMap[data.id] = {
      id: data.id,
      nom: data.name || 'Sans nom'
    };
  }
}

// Passer les données et le map au node suivant
return [{
  json: {
    dossiersMap: dossiersMap,
    totalDossiers: Object.keys(dossiersMap).length,
    items: items.map(i => i.json)
  }
}];

// CONFIGURATION: Nom du dossier cible (insensible à la casse)
const DOSSIER_CIBLE = 'template rapport';

// Récupérer les données
const prevData = $('Index Dossiers').first().json;
const dossiersMap = prevData.dossiersMap || {};
const filesWithParents = $input.all();

// Trouver l'ID du dossier cible
let dossierCibleId = null;
let dossierCibleNom = null;

for (const [id, info] of Object.entries(dossiersMap)) {
  const nomLower = info.nom.toLowerCase().trim();
  const cibleLower = DOSSIER_CIBLE.toLowerCase().trim();
  if (nomLower === cibleLower || 
      nomLower === cibleLower.replace(/ /g, '_') ||
      nomLower === cibleLower.replace(/ /g, '')) {
    dossierCibleId = id;
    dossierCibleNom = info.nom;
    break;
  }
}

// Si dossier cible non trouvé
if (!dossierCibleId) {
  return [{
    json: {
      success: false,
      timestamp: new Date().toISOString(),
      message: `Dossier '${DOSSIER_CIBLE}' non trouvé`,
      dossierRecherche: DOSSIER_CIBLE,
      dossiersDisponibles: Object.values(dossiersMap).map(d => d.nom).slice(0, 30),
      contenu: []
    }
  }];
}

// Filtrer les fichiers qui sont dans le dossier cible
const contenuDossier = [];

for (const item of filesWithParents) {
  const data = item.json;
  if (!data || !data.id) continue;

  // Vérifier si le fichier est dans le dossier cible
  const parents = data.parents || [];
  if (parents.includes(dossierCibleId)) {
    contenuDossier.push({
      fichier_id: data.id,
      fichier_nom: data.name || 'Sans nom',
      fichier_type: data.mimeType === 'application/vnd.google-apps.folder' ? 'dossier' : 'fichier',
      fichier_mimeType: data.mimeType || 'unknown',
      dossier_parent_id: dossierCibleId,
      dossier_parent_nom: dossierCibleNom
    });
  }
}

// Construire la réponse
return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    dossierCible: {
      id: dossierCibleId,
      nom: dossierCibleNom
    },
    statistiques: {
      totalElements: contenuDossier.length,
      sousDossiers: contenuDossier.filter(e => e.fichier_type === 'dossier').length,
      fichiers: contenuDossier.filter(e => e.fichier_type === 'fichier').length
    },
    contenu: contenuDossier
  }
}];
